import React, { useState } from 'react';
import { Bot, CalendarDays, Database, Trash2, Plus, Building2, Cpu, CalendarClock } from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState('fcst');
  const [mappingRules, setMappingRules] = useState(() => {
    const saved = localStorage.getItem('pskMasterData');
    return saved ? JSON.parse(saved) : {
      lineMap: { 'T1': 'SEC-T1(USA)', 'P1F': 'SEC-P1(F)(KR)' },
      modelMap: { 'SUPRA-N': { model: 'SUPRA N', pm: 0 } },
      atmMaster: [{ id: 'ATM-102', start: '2026-01-13', end: '2026-01-29', maxCapa: 6 }]
    };
  });

  const saveRules = (newRules) => { setMappingRules(newRules); localStorage.setItem('pskMasterData', JSON.stringify(newRules)); };

  // --- 기능 로직 복구 ---
  const addLine = (line, fab) => { saveRules({ ...mappingRules, lineMap: { ...mappingRules.lineMap, [line]: fab } }); };
  const removeLine = (line) => { const updated = { ...mappingRules }; delete updated.lineMap[line]; saveRules(updated); };

  const addModel = (raw, model, pm) => { saveRules({ ...mappingRules, modelMap: { ...mappingRules.modelMap, [raw]: { model, pm: parseInt(pm) } } }); };
  const removeModel = (raw) => { const updated = { ...mappingRules }; delete updated.modelMap[raw]; saveRules(updated); };

  const addAtm = (id, start, end, capa) => { saveRules({ ...mappingRules, atmMaster: [...mappingRules.atmMaster, { id, start, end, maxCapa: parseInt(capa) }] }); };
  const removeAtm = (id) => { saveRules({ ...mappingRules, atmMaster: mappingRules.atmMaster.filter(a => a.id !== id) }); };

  return (
    <div className="flex h-screen bg-gray-50">
      <aside className="w-64 bg-slate-900 text-white p-6 shadow-xl">
        <h1 className="text-xl font-bold mb-8 flex items-center"><Bot className="mr-2 text-blue-400" /> PSK Portal</h1>
        <button onClick={() => setActiveTab('fcst')} className={`w-full text-left p-3 rounded mb-2 ${activeTab === 'fcst' ? 'bg-blue-600' : 'hover:bg-slate-800'}`}><CalendarDays className="inline mr-2" size={18}/> FCST 스케줄러</button>
        <button onClick={() => setActiveTab('master')} className={`w-full text-left p-3 rounded ${activeTab === 'master' ? 'bg-blue-600' : 'hover:bg-slate-800'}`}><Database className="inline mr-2" size={18}/> 마스터 데이터 관리</button>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        {activeTab === 'master' ? (
          <div className="space-y-8">
            <h2 className="text-2xl font-bold">마스터 데이터 관리</h2>

            {/* 라인 매핑 */}
            <div className="bg-white p-6 rounded shadow border">
              <h3 className="font-bold mb-4 flex items-center"><Building2 className="mr-2"/> 라인 매핑 관리</h3>
              <div className="flex gap-2 mb-4">
                <input id="lineKey" className="border p-2" placeholder="라인명" />
                <input id="lineFab" className="border p-2" placeholder="FAB명" />
                <button onClick={() => addLine(document.getElementById('lineKey').value, document.getElementById('lineFab').value)} className="bg-blue-600 text-white px-4 py-2 rounded flex items-center"><Plus size={16}/> 추가</button>
              </div>
              {Object.entries(mappingRules.lineMap).map(([k, v]) => (
                <div key={k} className="flex justify-between p-2 border-b">{k} ➡️ {v} <button onClick={() => removeLine(k)} className="text-red-500"><Trash2 size={16}/></button></div>
              ))}
            </div>

            {/* 모델 매핑 */}
            <div className="bg-white p-6 rounded shadow border">
              <h3 className="font-bold mb-4 flex items-center"><Cpu className="mr-2"/> 모델 매핑 관리</h3>
              <div className="flex gap-2 mb-4">
                <input id="modKey" className="border p-2" placeholder="Raw 모델명" />
                <input id="modName" className="border p-2" placeholder="변환 모델명" />
                <input id="modPm" className="border p-2 w-16" placeholder="PM" />
                <button onClick={() => addModel(document.getElementById('modKey').value, document.getElementById('modName').value, document.getElementById('modPm').value)} className="bg-blue-600 text-white px-4 py-2 rounded flex items-center"><Plus size={16}/> 추가</button>
              </div>
              {Object.entries(mappingRules.modelMap).map(([k, v]) => (
                <div key={k} className="flex justify-between p-2 border-b">{k} ➡️ {v.model} (PM:{v.pm}) <button onClick={() => removeModel(k)} className="text-red-500"><Trash2 size={16}/></button></div>
              ))}
            </div>
          </div>
        ) : (
          <div className="bg-white p-6 rounded shadow border">
             <h2 className="text-xl font-bold">FCST 배정 화면</h2>
             <p className="mt-4 text-gray-500">데이터 배정 기능이 활성화되어 있습니다.</p>
          </div>
        )}
      </main>
    </div>
  );
}
